INSERT INTO `ai_chat_messages` (`id`, `session_id`, `role`, `content`, `created_at`) VALUES
(1, 'session_wsx', 'user', '现在有几个飞行任务，完成情况分别怎么样', '2026-04-09 10:19:10'),
(2, 'session_wsx', 'assistant', '您好，目前平台上共有3个飞行任务，分别是：\n\n1. 第三次任务：状态为“待起飞”，阶段为“待命”，进度为0%  \n2. 第二次任务：状态为“待起飞”，阶段为“待命”，进度为0%  \n3. 第一次任务：状态为“待起飞”，阶段为“待命”，进度为0%\n\n目前所有任务都还未开始执行，进度均为0%。如需查看详细任务信息或进行任务操作，可跳转至飞行任务管理页面。[NAV:flight]\n\n如果需要帮助启动任务或分析任务未执行原因，请告知，我可以为您提供操作建议。', '2026-04-09 10:19:14'),
(3, 'session_wsx', 'user', '他们分别的起点终点是什么', '2026-04-09 10:19:46'),
(4, 'session_wsx', 'assistant', '当前平台共有4架无人机，但全部处于离线状态。由于无人机离线，无法获取实时的起点和终点信息。如果需要查询历史任务的起点和终点，可以进入飞行任务管理页面查看任务详情。\n\n如需进一步了解无人机的历史任务起点和终点，请点击跳转：[NAV:flight]\n\n如果有具体无人机编号或名称，也可以告诉我，我帮您查找对应的任务信息。', '2026-04-09 10:19:50'),
(5, 'session_wsx', 'user', '现在各个无人机的电量状态怎么样，都可以直接飞行吗', '2026-04-09 10:23:58'),
(6, 'session_wsx', 'assistant', '您好，目前各个无人机的电池状态如下：\n\n1. 主机测试：  \n   - 电量：95%~98%  \n   - 温度：32.2°C~32.6°C  \n   - 电压：12.50V  \n   - 状态：正常\n\n电池电量充足，温度和电压均处于安全范围，理论上电池状态适合直接飞行。\n\n但需要注意：\n- 所有无人机当前都处于离线状态，无法直接执行飞行任务。  \n- 请先确认无人机是否可以上线，检查网络连接、设备电源等。\n\n建议操作：\n1. 检查无人机设备是否开机并连接到平台。\n2. 确认无人机上线后，再进行飞行任务操作。\n\n如需跳转到无人机管理页面进行设备状态检查，请点击：[NAV:drones]\n\n如需查看电池详细监控，请点击：[NAV:battery]', '2026-04-09 10:24:03');
